def sieve_of_eratosthenes(n):
    primes = [True] * (n + 1)
    p = 2
    while (p * p <= n):
        if (primes[p] == True):
            for i in range(p * p, n + 1, p):
                primes[i] = False
        p += 1
    prime_numbers = []
    for p in range(2, n):
        if primes[p]:
            prime_numbers.append(p)
    return prime_numbers

def find_prime_pairs(n):
    primes = sieve_of_eratosthenes(n)
    prime_set = set(primes)
    result = []
    for x in primes:
        y = n - x
        if y in prime_set and x <= y:
            result.append([x, y])
    return result

